class Solution:
    def searchRange(self, nums: List[int], target: int) -> List[int]:
        def bs(left_bias):
            l, r, ans = 0, len(nums)-1, -1
            while l <= r:
                m = (l+r)//2
                if nums[m] == target:
                    ans = m
                    if left_bias: r = m-1
                    else: l = m+1
                elif nums[m] < target: l = m+1
                else: r = m-1
            return ans
        return [bs(True), bs(False)]

